  36→        return bearerMatch[1].trim();
  37→    }
  38→
  39→    return trimmed;
  40→};
  41→
  42→const resolveAuthUser = async (token) => {
  43→    if (!token) {
  44→        return { user: null, error: null };
  45→    }
  46→
  47→    const { data: authData, error: authError } = await supabase.auth.getUser(token);
  48→    if (authError || !authData?.user?.id) {
  49→        return { user: null, error: authError || new Error("missing user id") };
  50→    }
  51→
  52→    return { user: authData.user, error: null };
  53→};
  54→
  55→const requireAuth = async (req, res, next) => {
  56→    const token = extractBearerToken(req.headers?.authorization);
  57→    if (!token) {
  58→        return res.status(401).json({ error: 'not authorized' });
  59→    }
  60→
  61→    const { user, error } = await resolveAuthUser(token);
  62→    if (error || !user?.id) {
  63→        console.error('auth middleware error:', error?.message || 'missing user id');
  64→        return res.status(401).json({ error: 'not authorized' });
  65→    }
  66→
  67→    req.userId = user.id;
  68→    req.authUser = user;
  69→    return next();
  70→};
  71→
  72→const optionalAuth = async (req, _res, next) => {
  73→    const token = extractBearerToken(req.headers?.authorization);
  74→    if (!token) {
  75→        return next();
  76→    }
  77→
  78→    const { user } = await resolveAuthUser(token);
  79→    if (user?.id) {
  80→        req.userId = user.id;
  81→        req.authUser = user;
  82→    }
  83→
  84→    return next();
  85→};
