 340→router.get('/getNotifications', requireAuth, async(req, res) =>{
 341→    const {before} = req.query;
 342→    const userId = req.userId;
 343→    const parsedLimit = parseLimitWithinRange(
 344→        req.query.limit,
 345→        NOTIFICATION_LIMIT_MIN,
 346→        NOTIFICATION_LIMIT_MAX,
 347→        NOTIFICATION_DEFAULT_LIMIT
 348→    );
 349→
 350→    if(parsedLimit == null){
 351→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
 352→    }
 353→
 354→    // Fetch a generous amount from both tables, then merge and paginate
 355→    const fetchLimit = parsedLimit + 1;
 356→
 357→    let journalQuery = supabase
 358→    .from('notifications')
 359→    .select(NOTIFICATION_JOURNAL_SELECT)
 360→    .eq('receiver_id', userId)
 361→    .order('created_at', {ascending: false})
 362→    .order('id', {ascending: false})
 363→    .limit(fetchLimit)
 364→
 365→    let opinionQuery = supabase
 366→    .from('notification_opinions')
 367→    .select(NOTIFICATION_OPINION_SELECT)
 368→    .eq('receiver_id', userId)
 369→    .order('created_at', {ascending: false})
 370→    .order('id', {ascending: false})
 371→    .limit(fetchLimit)
 372→
 373→    if(before){
 374→        journalQuery = journalQuery.lt('created_at', before);
 375→        opinionQuery = opinionQuery.lt('created_at', before);
 376→    }
 377→
 378→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 379→
 380→    if(journalResult.error){
 381→        console.error('error while fetching data from notification table:', journalResult.error);
 382→        return res.status(500).json({error: 'error fetching data from notification table'});
 383→    }
 384→    if(opinionResult.error){
 385→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 386→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 387→    }
 388→
 389→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 390→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 391→
 392→    // Merge and sort by created_at descending
 393→    const merged = [...journalNotifs, ...opinionNotifs]
 394→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 395→
 396→    // Likes/bookmarks lookup only for journal notifications
 397→    const journalIds = [...new Set(
 398→        merged
 399→            .filter((n) => n.source === 'journal')
 400→            .map((n) => n.journal_id)
 401→            .filter(Boolean)
 402→    )];
 403→
 404→    let hasLikedResult = [];
 405→    let hasBookMarkedResult = [];
 406→    if(journalIds.length > 0){
 407→        const [hasLiked, hasBookMarked] = await Promise.all([
 408→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 409→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 410→        ]);
 411→
 412→        if(hasLiked.error || hasBookMarked.error){
 413→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 414→        }
 415→        hasLikedResult = hasLiked.data || [];
 416→        hasBookMarkedResult = hasBookMarked.data || [];
 417→    }
 418→
 419→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 420→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 421→
 422→    const formatted = merged.map((notif) => ({
 423→        ...notif,
 424→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 425→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 426→    }))
 427→
 428→    const hasMore = formatted.length > parsedLimit;
 429→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
 430→
 431→    return res.status(200).json(
 432→        {
 433→            hasMore: hasMore,
 434→            data: slicedData,
 435→        }
 436→    )
 437→
 438→})
